import { useMemo, useRef, useState } from "react";

import base from "./pizza_base.png";

const toppings = ["🍄", "🧀", "🌽", "🍍", "🧅", "🌶️", "🫑"];

const toppingPrices = {
  "🍄": 40,
  "🧀": 45,
  "🌽": 30,
  "🍍": 35,
  "🧅": 20,
  "🌶️": 25,
  "🫑": 30,
};

const BASE_PRICE = 299;
const IMAGE_SIZE = 500;

export default function PizzaBuilder() {
  const [selected, setSelected] = useState(toppings[0]);
  const [pizza, setPizza] = useState([]);

  const imageRef = useRef(null);

  function handlePizzaClick(e) {
    const rect = e.currentTarget.getBoundingClientRect();

    setPizza((pizza) => [
      ...pizza,
      {
        topping: selected,
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
      },
    ]);
  }

  const scale = useMemo(() => {
    if (!imageRef.current) return 1;
    return imageRef.current.getBoundingClientRect().width / IMAGE_SIZE;
  });

  function calculateTotal() {
    return pizza.reduce(
      (total, { topping }) => total + toppingPrices[topping],
      BASE_PRICE
    );
  }

  return (
    <main>
      <h1>🍕 Pizza Builder</h1>

      <h2>Total: ₹{calculateTotal()}</h2>

      <p>
        {toppings.map((topping) => (
          <button
            key={topping}
            onClick={() => setSelected(topping)}
            disabled={selected === topping}
          >
            {topping}
          </button>
        ))}
      </p>

      <figure
        style={{
          position: "relative",
          display: "inline-block",
          margin: 0,
        }}
      >
        <img
          ref={imageRef}
          src={base}
          alt="Pizza"
          onClick={handlePizzaClick}
          style={{
            width: IMAGE_SIZE,
            maxWidth: "100%",
            display: "block",
            cursor: "crosshair",
          }}
        />

        {pizza.map(({ topping, x, y }, index) => (
          <span
            key={index}
            style={{
              position: "absolute",
              left: x * scale,
              top: y * scale,
            //   transform: "translate(-50%, -50%)",
              fontSize: "1.5rem",
              pointerEvents: "none",
            }}
          >
            {topping}
          </span>
        ))}
      </figure>
    </main>
  );
}
